const E=384,c=[.485,.456,.406],e=[.229,.224,.225];function I(r){const o=Math.max(...r),a=Array.from(r).map(t=>Math.exp(t-o)),s=a.reduce((t,n)=>t+n,0);return a.map(t=>t/s)}function m(r){const{data:o}=r,a=384*384,s=new Float32Array(3*a);for(let t=0;t<a;t++){const n=t*4;s[t]=(o[n]/255-c[0])/e[0],s[a+t]=(o[n+1]/255-c[1])/e[1],s[2*a+t]=(o[n+2]/255-c[2])/e[2]}return s}export{E as M,m as p,I as s};
